/* ===== 自定义变量 ===== */
:root {
    --primary-color: #0d6efd;      /* Bootstrap 主蓝色 */
    --secondary-color: #6c757d;    /* Bootstrap 次要灰色 */
    --success-color: #198754;      /* 成功绿色 */
    --warning-color: #ffc107;      /* 警告黄色 */
    --danger-color: #dc3545;       /* 危险红色 */
    --light-color: #f8f9fa;        /* 浅色背景 */
    --dark-color: #212529;         /* 深色文字 */

    /* 自定义品牌颜色 */
    --brand-blue: #0066cc;         /* 品牌蓝色 */
    --brand-light-blue: #e3f2fd;   /* 浅品牌蓝 */
    --accent-orange: #ff6b35;      /* 强调橙色 */

    /* 字体 */
    --font-family-sans: 'Segoe UI', 'Microsoft YaHei', 'PingFang SC', sans-serif;
    --font-family-serif: Georgia, 'Times New Roman', serif;

    /* 间距 */
    --spacing-xs: 0.5rem;
    --spacing-sm: 1rem;
    --spacing-md: 2rem;
    --spacing-lg: 3rem;
    --spacing-xl: 5rem;

    /* 圆角 */
    --border-radius-sm: 0.25rem;
    --border-radius-md: 0.5rem;
    --border-radius-lg: 1rem;

    /* 阴影 */
    --shadow-sm: 0 0.125rem 0.25rem rgba(0, 0, 0, 0.075);
    --shadow-md: 0 0.5rem 1rem rgba(0, 0, 0, 0.15);
    --shadow-lg: 0 1rem 3rem rgba(0, 0, 0, 0.175);
}

/* ===== 全局样式 ===== */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: var(--font-family-sans);
    color: var(--dark-color);
    line-height: 1.6;
    overflow-x: hidden;
}

/* ===== 通用类 ===== */
.section-padding {
    padding-top: var(--spacing-xl);
    padding-bottom: var(--spacing-xl);
}

.bg-light-custom {
    background-color: var(--brand-light-blue) !important;
}

.text-brand {
    color: var(--brand-blue) !important;
}

.btn-brand {
    background-color: var(--brand-blue);
    border-color: var(--brand-blue);
    color: white;
}

.btn-brand:hover {
    background-color: #0052a3;
    border-color: #0052a3;
    color: white;
}

/* ===== 导航栏 ===== */
.navbar-brand img {
    height: 40px;
    width: auto;
}

.navbar {
    box-shadow: var(--shadow-sm);
    transition: all 0.3s ease;
}

.navbar-scrolled {
    background-color: white !important;
    box-shadow: var(--shadow-md);
}

.nav-link {
    font-weight: 500;
    padding: 0.5rem 1rem !important;
    transition: color 0.3s ease;
}

.nav-link:hover {
    color: var(--brand-blue) !important;
}

.language-switcher .btn {
    padding: 0.25rem 0.75rem;
    font-size: 0.875rem;
}

/* ===== 页头区域 ===== */
.page-header {
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
    position: relative;
    overflow: hidden;
}

.page-header::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-image: url('../images/pattern.png');
    background-size: 300px;
    opacity: 0.1;
    pointer-events: none;
}

/* ===== 英雄区域 ===== */
.hero-section {
    background: linear-gradient(to right, #f8f9fa, #e9ecef);
    position: relative;
    overflow: hidden;
}

.hero-section::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 100%;
    height: 200%;
    background: radial-gradient(circle, rgba(13, 110, 253, 0.1) 0%, transparent 70%);
    z-index: 0;
}

.hero-section .container {
    position: relative;
    z-index: 1;
}

.hero-image-placeholder {
    position: relative;
    overflow: hidden;
}

.hero-image-placeholder::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(45deg, rgba(0, 102, 204, 0.1), rgba(255, 107, 53, 0.1));
}

/* ===== 卡片样式 ===== */
.card {
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    border: none;
}

.card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-lg) !important;
}

.card .feature-icon,
.card .customization-icon,
.card .equipment-icon,
.card .certification-icon {
    width: 80px;
    height: 80px;
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1.5rem;
    color: white;
}

/* ===== 时间线样式 ===== */
.timeline {
    position: relative;
    padding-left: 3rem;
    margin: 2rem 0;
}

.timeline::before {
    content: '';
    position: absolute;
    left: 1.5rem;
    top: 0;
    bottom: 0;
    width: 2px;
    background-color: var(--primary-color);
    opacity: 0.3;
}

.timeline-item {
    position: relative;
    margin-bottom: 2rem;
}

.timeline-item:last-child {
    margin-bottom: 0;
}

.timeline-date {
    position: absolute;
    left: -3rem;
    top: 0;
    background-color: var(--primary-color);
    color: white;
    padding: 0.25rem 0.75rem;
    border-radius: var(--border-radius-sm);
    font-weight: bold;
    font-size: 0.875rem;
}

.timeline-content {
    background-color: white;
    padding: 1.5rem;
    border-radius: var(--border-radius-md);
    box-shadow: var(--shadow-sm);
    border-left: 4px solid var(--primary-color);
}

/* 定制流程时间线 */
.timeline-process {
    position: relative;
    padding: 2rem 0;
}

.process-step {
    position: relative;
    margin-bottom: 3rem;
    padding-left: 4rem;
}

.process-step:last-child {
    margin-bottom: 0;
}

.process-step::before {
    content: '';
    position: absolute;
    left: 1.75rem;
    top: 0;
    bottom: -3rem;
    width: 2px;
    background-color: var(--primary-color);
    opacity: 0.2;
}

.process-step:last-child::before {
    display: none;
}

.step-number {
    position: absolute;
    left: 0;
    top: 0;
    width: 3.5rem;
    height: 3.5rem;
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    font-weight: bold;
    z-index: 1;
}

.step-content {
    background-color: white;
    padding: 1.5rem;
    border-radius: var(--border-radius-md);
    box-shadow: var(--shadow-md);
}

.step-details {
    margin-top: 1rem;
    padding-left: 1.5rem;
}

.step-details li {
    margin-bottom: 0.5rem;
    color: var(--secondary-color);
}

/* ===== 产品网格 ===== */
.products-grid .card {
    height: 100%;
}

.product-image-placeholder {
    height: 200px;
    background-color: #f8f9fa;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--secondary-color);
}

.product-category {
    font-size: 0.875rem;
    color: var(--brand-blue);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.product-price {
    font-size: 1.25rem;
    font-weight: bold;
    color: var(--brand-blue);
}

/* ===== 联系表单 ===== */
.contact-form .form-control,
.contact-form .form-select {
    border: 1px solid #dee2e6;
    padding: 0.75rem 1rem;
    transition: all 0.3s ease;
}

.contact-form .form-control:focus,
.contact-form .form-select:focus {
    border-color: var(--brand-blue);
    box-shadow: 0 0 0 0.25rem rgba(0, 102, 204, 0.25);
}

.contact-form label {
    font-weight: 500;
    margin-bottom: 0.5rem;
}

/* ===== 页脚 ===== */
.footer {
    background-color: var(--dark-color);
    color: white;
    padding: 3rem 0 1.5rem;
}

.footer-links h5 {
    color: white;
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.footer-links ul {
    list-style: none;
    padding-left: 0;
}

.footer-links li {
    margin-bottom: 0.75rem;
}

.footer-links a {
    color: rgba(255, 255, 255, 0.8);
    text-decoration: none;
    transition: color 0.3s ease;
}

.footer-links a:hover {
    color: white;
    text-decoration: underline;
}

.footer-social .social-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    background-color: rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: white;
    text-decoration: none;
    transition: all 0.3s ease;
    margin-right: 0.5rem;
}

.footer-social .social-icon:hover {
    background-color: var(--brand-blue);
    transform: translateY(-3px);
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    padding-top: 1.5rem;
    margin-top: 2rem;
    text-align: center;
    color: rgba(255, 255, 255, 0.6);
    font-size: 0.875rem;
}

/* ===== 合作伙伴标志 ===== */
.partner-logo-placeholder {
    transition: all 0.3s ease;
}

.partner-logo-placeholder:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-md) !important;
}

/* ===== 团队头像 ===== */
.team-avatar {
    width: 100px;
    height: 100px;
    margin: 0 auto 1.5rem;
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
}

/* ===== 图片占位符 ===== */
.image-placeholder {
    background-color: #f8f9fa;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--secondary-color);
    border-radius: var(--border-radius-md);
}

.image-placeholder i {
    opacity: 0.5;
}

/* ===== 响应式设计 ===== */
@media (max-width: 768px) {
    .timeline {
        padding-left: 2rem;
    }

    .timeline::before {
        left: 1rem;
    }

    .timeline-date {
        left: -2.5rem;
        font-size: 0.75rem;
        padding: 0.2rem 0.5rem;
    }

    .process-step {
        padding-left: 3rem;
    }

    .step-number {
        width: 2.5rem;
        height: 2.5rem;
        font-size: 1rem;
    }

    .section-padding {
        padding-top: var(--spacing-lg);
        padding-bottom: var(--spacing-lg);
    }

    .hero-section .display-4 {
        font-size: 2.5rem;
    }
}

@media (max-width: 576px) {
    .navbar-brand img {
        height: 30px;
    }

    .hero-section .display-4 {
        font-size: 2rem;
    }

    .page-header .display-4 {
        font-size: 2.5rem;
    }

    .card .feature-icon,
    .card .customization-icon,
    .card .equipment-icon,
    .card .certification-icon {
        width: 60px;
        height: 60px;
        margin-bottom: 1rem;
    }

    .card .feature-icon i,
    .card .customization-icon i,
    .card .equipment-icon i,
    .card .certification-icon i {
        font-size: 1.5rem;
    }
}

/* ===== 动画效果 ===== */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.fade-in-up {
    animation: fadeInUp 0.6s ease forwards;
}

/* ===== 加载动画 ===== */
.loading-spinner {
    display: inline-block;
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid rgba(0, 102, 204, 0.3);
    border-radius: 50%;
    border-top-color: var(--brand-blue);
    animation: spin 1s linear infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

/* ===== 实用工具类 ===== */
.text-shadow {
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
}

.box-shadow-hover {
    transition: box-shadow 0.3s ease;
}

.box-shadow-hover:hover {
    box-shadow: var(--shadow-lg);
}

.rounded-corners {
    border-radius: var(--border-radius-lg);
}

.gradient-primary {
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
}

.gradient-light {
    background: linear-gradient(135deg, #f8f9fa, #e9ecef);
}

/* ===== 打印样式 ===== */
@media print {
    .no-print {
        display: none !important;
    }

    body {
        font-size: 12pt;
        line-height: 1.5;
    }

    .container {
        width: 100%;
        max-width: 100%;
        padding: 0;
    }

    .card {
        box-shadow: none !important;
        border: 1px solid #dee2e6;
    }
}

