    margin-bottom: 0.75rem;
}

.footer-links a {
    color: rgba(255, 255, 255, 0.8);
    text-decoration: none;
    transition: color 0.3s ease;
}

.footer-links a:hover {
    color: white;
    text-decoration: underline;
}

.footer-social .social-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 40px;
    height: 40px;
    background-color: rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: white;
    text-decoration: none;
    transition: all 0.3s ease;
    margin-right: 0.5rem;
}

.footer-social .social-icon:hover {
    background-color: var(--brand-blue);
    transform: translateY(-3px);
}

.footer-bottom {
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    padding-top: 1.5rem;
    margin-top: 2rem;
    text-align: center;
    color: rgba(255, 255, 255, 0.6);
    font-size: 0.875rem;
}

/* ===== 合作伙伴标志 ===== */
.partner-logo-placeholder {
    transition: all 0.3s ease;
}

.partner-logo-placeholder:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-md) !important;
}

/* ===== 团队头像 ===== */
.team-avatar {
    width: 100px;
    height: 100px;
    margin: 0 auto 1.5rem;
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
}

/* ===== 图片占位符 ===== */
.image-placeholder {
    background-color: #f8f9fa;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--secondary-color);
    border-radius: var(--border-radius-md);
}

.image-placeholder i {
    opacity: 0.5;
}

/* ===== 响应式设计 ===== */
@media (max-width: 768px) {
    .timeline {
        padding-left: 2rem;
    }

    .timeline::before {
        left: 1rem;
    }

    .timeline-date {
        left: -2.5rem;
        font-size: 0.75rem;
        padding: 0.2rem 0.5rem;
    }

    .process-step {
        padding-left: 3rem;
    }

    .step-number {
        width: 2.5rem;
        height: 2.5rem;
        font-size: 1rem;
    }

    .section-padding {
        padding-top: var(--spacing-lg);
        padding-bottom: var(--spacing-lg);
    }

    .hero-section .display-4 {
        font-size: 2.5rem;
    }
}

@media (max-width: 576px) {
    .navbar-brand img {
        height: 30px;
    }

    .hero-section .display-4 {
        font-size: 2rem;
    }

    .page-header .display-4 {
        font-size: 2.5rem;
    }

    .card .feature-icon,
    .card .customization-icon,
    .card .equipment-icon,
    .card .certification-icon {
        width: 60px;
        height: 60px;
        margin-bottom: 1rem;
    }

    .card .feature-icon i,
    .card .customization-icon i,
    .card .equipment-icon i,
    .card .certification-icon i {
        font-size: 1.5rem;
    }
}

/* ===== 动画效果 ===== */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.fade-in-up {
    animation: fadeInUp 0.6s ease forwards;
}

/* ===== 加载动画 ===== */
.loading-spinner {
    display: inline-block;
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid rgba(0, 102, 204, 0.3);
    border-radius: 50%;
    border-top-color: var(--brand-blue);
    animation: spin 1s linear infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

/* ===== 实用工具类 ===== */
.text-shadow {
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
}

.box-shadow-hover {
    transition: box-shadow 0.3s ease;
}

.box-shadow-hover:hover {
    box-shadow: var(--shadow-lg);
}

.rounded-corners {
    border-radius: var(--border-radius-lg);
}

.gradient-primary {
    background: linear-gradient(135deg, var(--brand-blue), #0047a3);
}

.gradient-light {
    background: linear-gradient(135deg, #f8f9fa, #e9ecef);
}

/* ===== 打印样式 ===== */
@media print {
    .no-print {
        display: none !important;
    }

    body {
        font-size: 12pt;
        line-height: 1.5;
    }

    .container {
        width: 100%;
        max-width: 100%;
        padding: 0;
    }

    .card {
        box-shadow: none !important;
        border: 1px solid #dee2e6;
    }
}

