/**
 * 益阳小星星服装 - 主JavaScript文件
 * 版本: 1.0
 * 日期: 2026-04-20
 */

// 页面加载完成后执行
document.addEventListener('DOMContentLoaded', function() {
    console.log('益阳小星星服装网站已加载');

    // 初始化组件
    initializeComponents();

    // 初始化事件监听器
    initializeEventListeners();

    // 检查用户语言偏好
    checkLanguagePreference();

    // 初始化滚动效果
    initializeScrollEffects();
});

/**
 * 初始化所有组件
 */
function initializeComponents() {
    // 加载导航栏和页脚
    loadNavbar();
    loadFooter();

    // 如果是首页，加载产品预览
    if (document.body.contains(document.getElementById('products-preview'))) {
        loadProductsPreview();
    }

    // 如果是产品页，初始化产品过滤器
    if (document.body.contains(document.getElementById('category-filters'))) {
        initializeProductFilters();
    }

    // 如果是联系页面，初始化表单
    if (document.body.contains(document.getElementById('contactForm'))) {
        initializeContactForm();
    }
}

/**
 * 初始化事件监听器
 */
function initializeEventListeners() {
    // 导航栏滚动效果
    window.addEventListener('scroll', handleNavbarScroll);

    // 语言切换器事件
    document.querySelectorAll('.lang-switcher').forEach(button => {
        button.addEventListener('click', handleLanguageSwitch);
    });

    // 产品类别筛选事件
    document.querySelectorAll('.category-btn').forEach(button => {
        button.addEventListener('click', handleCategoryFilter);
    });
}

/**
 * 加载导航栏
 */
function loadNavbar() {
    const navbarContainer = document.getElementById('navbar-container');
    if (!navbarContainer) return;

    const navbarHTML = `
        <nav class="navbar navbar-expand-lg navbar-light bg-white fixed-top">
            <div class="container">
                <a class="navbar-brand" href="index.html">
                    <div class="d-flex align-items-center">
                        <div class="brand-logo-placeholder me-2">
