                        </div>
                        <span class="fw-bold fs-5" data-i18n="nav.brand">益阳小星星服装</span>
                    </div>
                </a>

                <button class="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
                    <span class="navbar-toggler-icon"></span>
                </button>

                <div class="collapse navbar-collapse" id="navbarNav">
                    <ul class="navbar-nav ms-auto">
                        <li class="nav-item">
                            <a class="nav-link" href="index.html" data-i18n="nav.home">首页</a>
                        </li>
                        <li class="nav-item">
                            <a class="nav-link" href="about.html" data-i18n="nav.about">关于我们</a>
                        </li>
                        <li class="nav-item">
                            <a class="nav-link" href="products.html" data-i18n="nav.products">产品中心</a>
                        </li>
                        <li class="nav-item">
                            <a class="nav-link" href="customization.html" data-i18n="nav.customization">定制流程</a>
                        </li>
                        <li class="nav-item">
                            <a class="nav-link" href="strength.html" data-i18n="nav.strength">公司实力</a>
                        </li>
                        <li class="nav-item">
                            <a class="nav-link" href="contact.html" data-i18n="nav.contact">联系我们</a>
                        </li>
                    </ul>

                    <div class="language-switcher ms-lg-3 mt-3 mt-lg-0">
                        <div class="btn-group" role="group">
                            <button type="button" class="btn btn-outline-primary btn-sm lang-switcher" data-lang="zh" data-i18n="nav.langZh">中文</button>
                            <button type="button" class="btn btn-outline-primary btn-sm lang-switcher" data-lang="en" data-i18n="nav.langEn">English</button>
                        </div>
                    </div>
                </div>
            </div>
        </nav>
    `;

    navbarContainer.innerHTML = navbarHTML;

    // 设置当前页面激活状态
    setActiveNavLink();
}

/**
 * 设置当前页面导航链接激活状态
 */
function setActiveNavLink() {
    const currentPage = window.location.pathname.split('/').pop() || 'index.html';
    const navLinks = document.querySelectorAll('.nav-link');

    navLinks.forEach(link => {
        const href = link.getAttribute('href');
        if (href === currentPage || (currentPage === '' && href === 'index.html')) {
            link.classList.add('active');
            link.setAttribute('aria-current', 'page');
        } else {
            link.classList.remove('active');
            link.removeAttribute('aria-current');
        }
    });
}

/**
 * 加载页脚
 */
function loadFooter() {
    const footerContainer = document.getElementById('footer-container');
    if (!footerContainer) return;

    const footerHTML = `
        <footer class="footer">
            <div class="container">
                <div class="row">
                    <div class="col-lg-4 mb-4 mb-lg-0">
                        <div class="footer-brand mb-3">
                            <div class="d-flex align-items-center">
                                <div class="brand-logo-placeholder me-2">
                                    <i class="bi bi-stars text-white fs-4"></i>
                                </div>
                                <span class="fw-bold fs-5 text-white">益阳小星星服装</span>
                            </div>
                        </div>
                        <p class="text-white-50 mb-4" data-i18n="footer.description">
                            专业生产婴儿纯棉纱巾、穆斯林婴儿礼盒等母婴纺织品，7A级制造标准，全球B2B合作伙伴。
                        </p>
                        <div class="footer-social">
                            <a href="#" class="social-icon" title="Facebook">
                                <i class="bi bi-facebook"></i>
                            </a>
                            <a href="#" class="social-icon" title="LinkedIn">
                                <i class="bi bi-linkedin"></i>
                            </a>
                            <a href="#" class="social-icon" title="Instagram">
                                <i class="bi bi-instagram"></i>
                            </a>
                            <a href="#" class="social-icon" title="YouTube">
                                <i class="bi bi-youtube"></i>
                            </a>
                        </div>
                    </div>

                    <div class="col-lg-2 col-md-4 mb-4 mb-md-0">
                        <h5 class="text-white mb-4" data-i18n="footer.quickLinks">快速链接</h5>
                        <ul class="list-unstyled">
                            <li class="mb-2">
                                <a href="index.html" class="text-white-50" data-i18n="nav.home">首页</a>
                            </li>
                            <li class="mb-2">
                                <a href="about.html" class="text-white-50" data-i18n="nav.about">关于我们</a>
                            </li>
                            <li class="mb-2">
                                <a href="products.html" class="text-white-50" data-i18n="nav.products">产品中心</a>
                            </li>
                            <li class="mb-2">
                                <a href="customization.html" class="text-white-50" data-i18n="nav.customization">定制流程</a>
                            </li>
                        </ul>
                    </div>

                    <div class="col-lg-2 col-md-4 mb-4 mb-md-0">
                        <h5 class="text-white mb-4" data-i18n="footer.moreLinks">更多链接</h5>
                        <ul class="list-unstyled">
                            <li class="mb-2">
                                <a href="strength.html" class="text-white-50" data-i18n="nav.strength">公司实力</a>
                            </li>
                            <li class="mb-2">
                                <a href="contact.html" class="text-white-50" data-i18n="nav.contact">联系我们</a>
                            </li>
                            <li class="mb-2">
                                <a href="#" class="text-white-50" data-i18n="footer.privacy">隐私政策</a>
                            </li>
                            <li class="mb-2">
                                <a href="#" class="text-white-50" data-i18n="footer.terms">服务条款</a>
                            </li>
                        </ul>
                    </div>

                    <div class="col-lg-4 col-md-4">
                        <h5 class="text-white mb-4" data-i18n="footer.contactInfo">联系信息</h5>
                        <ul class="list-unstyled text-white-50">
                            <li class="mb-2">
                                <i class="bi bi-geo-alt me-2"></i>
                                <span data-i18n="footer.address">湖南省益阳市高新区创新工业园28号</span>
                            </li>
                            <li class="mb-2">
                                <i class="bi bi-telephone me-2"></i>
                                <span data-i18n="footer.phone">+86 737 8888 8888</span>
                            </li>
                            <li class="mb-2">
                                <i class="bi bi-envelope me-2"></i>
                                <span data-i18n="footer.email">sales@yiyangxiaoxingxing.com</span>
                            </li>
                            <li class="mb-2">
                                <i class="bi bi-whatsapp me-2"></i>
                                <span data-i18n="footer.whatsapp">+86 138 8888 8888</span>
                            </li>
                        </ul>
                    </div>
                </div>

                <div class="footer-bottom">
                    <div class="row align-items-center">
                        <div class="col-md-6 text-center text-md-start mb-2 mb-md-0">
                            <span data-i18n="footer.copyright">&copy; 2010-2026 益阳小星星服装有限公司 版权所有</span>
                        </div>
                        <div class="col-md-6 text-center text-md-end">
                            <span data-i18n="footer.icp">湘ICP备12345678号</span>
                        </div>
                    </div>
                </div>
            </div>
        </footer>
    `;

    footerContainer.innerHTML = footerHTML;
}

/**
 * 处理导航栏滚动效果
 */
function handleNavbarScroll() {
    const navbar = document.querySelector('.navbar');
    if (window.scrollY > 50) {
        navbar.classList.add('navbar-scrolled');
    } else {
        navbar.classList.remove('navbar-scrolled');
    }
}

/**
 * 处理语言切换
 */
function handleLanguageSwitch(event) {
    const lang = event.target.dataset.lang;
    if (lang && window.i18n) {
        window.i18n.switchLanguage(lang);
    }
}

/**
 * 检查用户语言偏好
 */
function checkLanguagePreference() {
    // 从localStorage获取语言偏好
    const preferredLang = localStorage.getItem('preferredLang');
    const browserLang = navigator.language.substring(0, 2);

    // 默认使用中文，如果浏览器语言是英文且用户没有设置偏好，使用英文
    if (!preferredLang && browserLang === 'en') {
        localStorage.setItem('preferredLang', 'en');
    }
}

/**
 * 初始化滚动效果
 */
function initializeScrollEffects() {
    // 使用Intersection Observer实现滚动动画
    const observerOptions = {
        threshold: 0.1,
        rootMargin: '0px 0px -50px 0px'
    };

    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('fade-in-up');
            }
        });
    }, observerOptions);

    // 观察需要动画的元素
    document.querySelectorAll('.card, .timeline-item, .process-step').forEach(el => {
        observer.observe(el);
    });
}

/**
 * 加载产品预览（首页用）
 */
function loadProductsPreview() {
    const productsPreview = document.getElementById('products-preview');
    if (!productsPreview) return;

    // 模拟产品数据
    const products = [
        {
            id: 1,
            name: '纯棉多层纱巾',
            category: 'towels',
            description: '120cm×120cm，6层纯棉，超强吸水性',
            price: '¥8.50'
        },
        {
            id: 2,
            name: '穆斯林婴儿礼盒',
            category: 'gift-sets',
            description: '包含纱巾、围嘴、帽子等7件套',
            price: '¥45.00'
        },
        {
            id: 3,
            name: '婴儿布尿裤',
            category: 'clothing',
            description: '可重复使用，环保透气',
            price: '¥12.00'
        },
        {
            id: 4,
            name: '婴儿围嘴',
            category: 'clothing',
            description: '防水背面，魔术贴设计',
            price: '¥6.50'
        }
    ];

    let productsHTML = '';
    products.forEach(product => {
        productsHTML += `
            <div class="col-md-3 col-sm-6">
                <div class="card border-0 shadow-sm h-100">
                    <div class="product-image-placeholder rounded-top">
                        <i class="bi bi-image display-4 text-muted"></i>
                    </div>
                    <div class="card-body">
                        <span class="product-category d-block mb-2">${product.category === 'towels' ? '纯棉纱巾' : product.category === 'gift-sets' ? '婴儿礼盒' : '婴儿服饰'}</span>
                        <h5 class="card-title fw-bold">${product.name}</h5>
                        <p class="card-text text-muted small">${product.description}</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="product-price">${product.price}</span>
                            <a href="products.html" class="btn btn-sm btn-outline-primary">查看详情</a>
                        </div>
                    </div>
                </div>
            </div>
        `;
    });

    productsPreview.innerHTML = productsHTML;
}

/**
 * 初始化产品过滤器
 */
function initializeProductFilters() {
    // 产品过滤逻辑将在products.js中实现
    console.log('产品过滤器已初始化');
}

/**
 * 处理产品类别筛选
 */
function handleCategoryFilter(event) {
    const category = event.currentTarget.dataset.category;

    // 更新按钮激活状态
    document.querySelectorAll('.category-btn').forEach(btn => {
        btn.classList.remove('active');
    });
    event.currentTarget.classList.add('active');

    // 在这里实现产品过滤逻辑
    console.log(`筛选类别: ${category}`);
}

/**
 * 初始化联系表单
 */
function initializeContactForm() {
    const contactForm = document.getElementById('contactForm');
    if (!contactForm) return;

    contactForm.addEventListener('submit', function(event) {
        event.preventDefault();

        // 表单验证
        if (validateContactForm()) {
            // 显示加载状态
            const submitBtn = contactForm.querySelector('button[type="submit"]');
            const originalText = submitBtn.innerHTML;
            submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>发送中...';
            submitBtn.disabled = true;

            // 模拟表单提交
            setTimeout(() => {
                showFormMessage('success', '询盘发送成功！我们将在24小时内回复您。');
                contactForm.reset();
                submitBtn.innerHTML = originalText;
                submitBtn.disabled = false;
            }, 2000);
        }
    });
}

/**
 * 验证联系表单
 */
function validateContactForm() {
    const name = document.getElementById('name').value.trim();
    const email = document.getElementById('email').value.trim();
    const message = document.getElementById('message').value.trim();

    if (!name) {
        showFormMessage('danger', '请输入您的姓名。');
        document.getElementById('name').focus();
        return false;
    }

    if (!email) {
        showFormMessage('danger', '请输入您的电子邮箱。');
        document.getElementById('email').focus();
        return false;
    }

    // 简单的邮箱验证
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
        showFormMessage('danger', '请输入有效的电子邮箱地址。');
        document.getElementById('email').focus();
        return false;
    }

    if (!message) {
        showFormMessage('danger', '请输入留言内容。');
        document.getElementById('message').focus();
        return false;
    }

    return true;
}

/**
 * 显示表单消息
 */
function showFormMessage(type, message) {
    const messageDiv = document.getElementById('formMessage');
    if (!messageDiv) return;

    messageDiv.className = `alert alert-${type}`;
    messageDiv.textContent = message;
    messageDiv.classList.remove('d-none');

    // 5秒后自动隐藏
    setTimeout(() => {
        messageDiv.classList.add('d-none');
    }, 5000);
}

// 导出函数供其他模块使用
window.utils = {
    validateContactForm,
    showFormMessage,
    setActiveNavLink
};

