/**
 * 初始化联系表单
 */
function initializeContactForm() {
    const contactForm = document.getElementById('contactForm');
    if (!contactForm) return;

    contactForm.addEventListener('submit', function(event) {
        event.preventDefault();

        // 表单验证
        if (validateContactForm()) {
            // 显示加载状态
            const submitBtn = contactForm.querySelector('button[type="submit"]');
            const originalText = submitBtn.innerHTML;
            submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>发送中...';
            submitBtn.disabled = true;

            // 模拟表单提交
            setTimeout(() => {
                showFormMessage('success', '询盘发送成功！我们将在24小时内回复您。');
                contactForm.reset();
                submitBtn.innerHTML = originalText;
                submitBtn.disabled = false;
            }, 2000);
        }
    });
}

/**
 * 验证联系表单
 */
function validateContactForm() {
    const name = document.getElementById('name').value.trim();
    const email = document.getElementById('email').value.trim();
    const message = document.getElementById('message').value.trim();

    if (!name) {
        showFormMessage('danger', '请输入您的姓名。');
        document.getElementById('name').focus();
        return false;
    }

    if (!email) {
        showFormMessage('danger', '请输入您的电子邮箱。');
        document.getElementById('email').focus();
        return false;
    }

    // 简单的邮箱验证
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
        showFormMessage('danger', '请输入有效的电子邮箱地址。');
        document.getElementById('email').focus();
        return false;
    }

    if (!message) {
        showFormMessage('danger', '请输入留言内容。');
        document.getElementById('message').focus();
        return false;
    }

    return true;
}

/**
 * 显示表单消息
 */
function showFormMessage(type, message) {
    const messageDiv = document.getElementById('formMessage');
    if (!messageDiv) return;

    messageDiv.className = `alert alert-${type}`;
    messageDiv.textContent = message;
    messageDiv.classList.remove('d-none');

    // 5秒后自动隐藏
    setTimeout(() => {
        messageDiv.classList.add('d-none');
    }, 5000);
}

// 导出函数供其他模块使用
window.utils = {
    validateContactForm,
    showFormMessage,
    setActiveNavLink
};

