/**
 * 益阳小星星服装 - 多语言系统
 * 版本: 1.0
 * 日期: 2026-04-20
 */

class I18n {
    constructor() {
        this.currentLang = localStorage.getItem('preferredLang') || 'zh';
        this.translations = {};
        this.initialized = false;
        this.init();
    }

    /**
     * 初始化多语言系统
     */
    async init() {
        try {
            await this.loadLanguage(this.currentLang);
            this.applyTranslations();
            this.setupLanguageSwitcher();
            this.initialized = true;
            console.log(`多语言系统已初始化，当前语言: ${this.currentLang}`);
        } catch (error) {
            console.error('多语言系统初始化失败:', error);
            // 加载失败时使用默认中文
            await this.loadDefaultTranslations();
            this.applyTranslations();
        }
    }

    /**
     * 加载语言文件
     */
    async loadLanguage(lang) {
        try {
            const response = await fetch(`locales/${lang}.json`);
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            this.translations = await response.json();
            this.currentLang = lang;
            localStorage.setItem('preferredLang', lang);
        } catch (error) {
            console.error(`加载语言文件 ${lang}.json 失败:`, error);
            throw error;
        }
    }

    /**
     * 加载默认翻译（中文）
     */
    async loadDefaultTranslations() {
        this.translations = {
            nav: {
                brand: "益阳小星星服装",
                home: "首页",
                about: "关于我们",
                products: "产品中心",
                customization: "定制流程",
                strength: "公司实力",
                contact: "联系我们",
                langZh: "中文",
                langEn: "English"
            },
            home: {
                title: "益阳小星星服装",
                subtitle: "您的全球顶级7A级制造合作伙伴，专业生产高品质母婴纺织品",
                viewProducts: "查看产品",
                contactUs: "联系我们",
                heroImage: "工厂形象展示",
                whyChooseUs: "为什么选择我们",
                whyChooseUsDesc: "我们提供卓越的品质、有竞争力的价格和可靠的供应链",
                feature1Title: "7A级制造标准",
                feature1Desc: "严格执行7A级质量标准，确保每一件产品都符合最高标准",
                feature2Title: "全球供应链",
                feature2Desc: "中国→迪拜→目标国的三角贸易模式，覆盖苏丹、埃及等市场",
                feature3Title: "认证齐全",
                feature3Desc: "ISO、OEKO-TEX等国际认证，符合穆斯林文化要求",
                featuredProducts: "主打产品",
                featuredProductsDesc: "高品质母婴纺织品，满足不同市场需求",
                viewAllProducts: "查看所有产品"
            }
        };
        this.currentLang = 'zh';
    }

    /**
     * 应用翻译到页面
     */
    applyTranslations() {
        // 翻译所有带有 data-i18n 属性的元素
        document.querySelectorAll('[data-i18n]').forEach(element => {
            const key = element.getAttribute('data-i18n');
            const translation = this.getTranslation(key);

            if (translation !== undefined) {
                this.applyTranslationToElement(element, translation);
            }
        });

        // 更新HTML语言属性
        document.documentElement.lang = this.currentLang;

        // 更新导航栏激活状态（如果存在）
        if (window.utils && window.utils.setActiveNavLink) {
            window.utils.setActiveNavLink();
        }
    }

    /**
     * 获取翻译文本
     */
    getTranslation(key) {
        if (!key) return undefined;

        const keys = key.split('.');
        let value = this.translations;

        for (const k of keys) {
            if (value && typeof value === 'object' && k in value) {
                value = value[k];
            } else {
                return undefined;
            }
        }

        return value;
    }

    /**
     * 应用翻译到特定元素
     */
    applyTranslationToElement(element, translation) {
        if (!element || translation === undefined) return;

        const tagName = element.tagName.toLowerCase();

        switch (tagName) {
            case 'input':
            case 'textarea':
                // 对于输入框，设置placeholder
                if (element.type !== 'submit' && element.type !== 'button') {
                    element.placeholder = translation;
                } else {
                    element.value = translation;
                }
                break;

            case 'img':
                // 对于图片，设置alt属性
                element.alt = translation;
                break;

            case 'button':
                // 对于按钮，检查是否是提交按钮
                if (element.type === 'submit' || element.type === 'button') {
                    element.textContent = translation;
                }
                break;

            case 'option':
                // 对于选项，设置文本内容
                element.textContent = translation;
                break;

            default:
                // 对于其他元素，设置文本内容
                element.textContent = translation;
                break;
        }

        // 设置翻译后的标题（如果有）
        if (element.hasAttribute('title')) {
            const titleKey = element.getAttribute('data-i18n-title');
            if (titleKey) {
                const titleTranslation = this.getTranslation(titleKey);
                if (titleTranslation !== undefined) {
                    element.title = titleTranslation;
                }
            }
        }
    }

    /**
     * 设置语言切换器
     */
    setupLanguageSwitcher() {
        document.querySelectorAll('.lang-switcher').forEach(button => {
            // 移除现有事件监听器
            const newButton = button.cloneNode(true);
            button.parentNode.replaceChild(newButton, button);

            // 添加新的事件监听器
            newButton.addEventListener('click', (e) => {
                const lang = e.target.dataset.lang;
                if (lang && lang !== this.currentLang) {
                    this.switchLanguage(lang);
                }
            });

            // 更新当前语言按钮状态
            if (newButton.dataset.lang === this.currentLang) {
                newButton.classList.add('active');
                newButton.classList.remove('btn-outline-primary');
                newButton.classList.add('btn-primary');
            } else {
                newButton.classList.remove('active');
                newButton.classList.remove('btn-primary');
                newButton.classList.add('btn-outline-primary');
            }
        });
    }

    /**
     * 切换语言
     */
    async switchLanguage(lang) {
        try {
            // 显示加载状态
            this.showLanguageLoading();

            await this.loadLanguage(lang);
            this.applyTranslations();
            this.setupLanguageSwitcher();

            // 显示切换成功消息
            this.showLanguageSuccess(lang);

            // 触发语言切换事件
            this.dispatchLanguageChangeEvent(lang);

        } catch (error) {
            console.error(`切换语言到 ${lang} 失败:`, error);
            this.showLanguageError();
        }
    }

    /**
     * 显示语言加载状态
     */
    showLanguageLoading() {
        // 这里可以添加加载动画
        console.log('正在切换语言...');
    }

    /**
     * 显示语言切换成功
     */
    showLanguageSuccess(lang) {
        // 这里可以添加成功提示
        console.log(`语言已切换到: ${lang}`);
    }

    /**
     * 显示语言切换错误
     */
    showLanguageError() {
        // 这里可以添加错误提示
        console.error('语言切换失败');
    }

    /**
     * 分发语言切换事件
     */
    dispatchLanguageChangeEvent(lang) {
        const event = new CustomEvent('languageChanged', {
            detail: { language: lang }
        });
        document.dispatchEvent(event);
    }

    /**
     * 获取当前语言
     */
    getCurrentLanguage() {
        return this.currentLang;
    }

    /**
     * 翻译单个文本
     */
    translate(key) {
        return this.getTranslation(key) || key;
    }

    /**
     * 翻译整个对象
     */
    translateObject(obj) {
        if (typeof obj !== 'object' || obj === null) return obj;

        const translated = Array.isArray(obj) ? [] : {};

        for (const key in obj) {
            if (typeof obj[key] === 'string') {
                translated[key] = this.translate(obj[key]);
            } else if (typeof obj[key] === 'object') {
                translated[key] = this.translateObject(obj[key]);
            } else {
                translated[key] = obj[key];
            }
        }

        return translated;
    }
}

