/**
 * 益阳小星星服装 - 表单处理模块
 * 版本: 1.0
 * 日期: 2026-04-20
 */

class FormHandler {
    constructor(formId, options = {}) {
        this.form = document.getElementById(formId);
        this.options = {
            successMessage: '表单提交成功！我们将在24小时内回复您。',
            errorMessage: '提交失败，请稍后重试。',
            loadingText: '发送中...',
            ...options
        };

        if (this.form) {
            this.init();
        }
    }

    init() {
        this.form.addEventListener('submit', this.handleSubmit.bind(this));
        this.setupValidation();
    }

    setupValidation() {
        // 实时验证
        this.form.querySelectorAll('[required]').forEach(input => {
            input.addEventListener('blur', () => this.validateField(input));
            input.addEventListener('input', () => this.clearFieldError(input));
        });
    }

    validateField(field) {
        const value = field.value.trim();
        const fieldName = field.name || field.id;

        if (!value) {
            this.showFieldError(field, '此字段为必填项');
            return false;
        }

        if (field.type === 'email') {
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(value)) {
                this.showFieldError(field, '请输入有效的电子邮箱地址');
                return false;
            }
        }

        if (field.type === 'tel') {
            const phoneRegex = /^[\d\s\-\+\(\)]+$/;
            if (!phoneRegex.test(value)) {
                this.showFieldError(field, '请输入有效的电话号码');
                return false;
            }
        }

        this.clearFieldError(field);
        return true;
    }

    showFieldError(field, message) {
        this.clearFieldError(field);

        const errorDiv = document.createElement('div');
        errorDiv.className = 'invalid-feedback d-block';
        errorDiv.textContent = message;
        errorDiv.id = `${field.id || field.name}-error`;

        field.classList.add('is-invalid');

        const parent = field.parentElement;
        if (parent.querySelector('.invalid-feedback')) {
            parent.removeChild(parent.querySelector('.invalid-feedback'));
        }
        parent.appendChild(errorDiv);
    }

    clearFieldError(field) {
        field.classList.remove('is-invalid');

        const errorId = `${field.id || field.name}-error`;
        const errorElement = document.getElementById(errorId);
        if (errorElement) {
            errorElement.remove();
        }
    }

    validateForm() {
        let isValid = true;
        const requiredFields = this.form.querySelectorAll('[required]');

        requiredFields.forEach(field => {
            if (!this.validateField(field)) {
                isValid = false;
            }
        });

        return isValid;
    }

    async handleSubmit(event) {
        event.preventDefault();

        if (!this.validateForm()) {
            this.showMessage('danger', '请检查表单中的错误');
            return;
        }

        // 获取表单数据
        const formData = new FormData(this.form);
        const submitButton = this.form.querySelector('button[type="submit"]');
        const originalText = submitButton.innerHTML;

        try {
            // 显示加载状态
            submitButton.innerHTML = `<span class="spinner-border spinner-border-sm me-2"></span>${this.options.loadingText}`;
            submitButton.disabled = true;

            // 模拟API调用
            await this.submitForm(formData);

            // 显示成功消息
            this.showMessage('success', this.options.successMessage);
            this.form.reset();

        } catch (error) {
            console.error('表单提交错误:', error);
            this.showMessage('danger', this.options.errorMessage);
        } finally {
            // 恢复按钮状态
            submitButton.innerHTML = originalText;
            submitButton.disabled = false;
        }
    }

    async submitForm(formData) {
        // 这里替换为实际的Formspree端点
        const formspreeEndpoint = 'https://formspree.io/f/your-form-id';

        // 模拟网络请求
        return new Promise((resolve, reject) => {
            setTimeout(() => {
                // 模拟成功响应
                const response = {
                    ok: true,
                    status: 200
                };

                if (response.ok) {
                    resolve(response);
                } else {
                    reject(new Error('表单提交失败'));
                }
            }, 2000);
        });

        // 实际使用时取消注释以下代码
        /*
        const response = await fetch(formspreeEndpoint, {
            method: 'POST',
            body: formData,
            headers: {
                'Accept': 'application/json'
            }
        });

        if (!response.ok) {
            throw new Error('表单提交失败');
        }

        return response;
        */
    }

    showMessage(type, message) {
        // 移除现有消息
        const existingMessage = this.form.querySelector('.form-message');
        if (existingMessage) {
            existingMessage.remove();
        }

        // 创建新消息
        const messageDiv = document.createElement('div');
        messageDiv.className = `alert alert-${type} form-message mt-3`;
        messageDiv.textContent = message;

        // 添加到表单
        const submitButton = this.form.querySelector('button[type="submit"]');
        this.form.insertBefore(messageDiv, submitButton.parentElement);

        // 5秒后自动隐藏
        setTimeout(() => {
            if (messageDiv.parentElement) {
                messageDiv.remove();
            }
        }, 5000);
    }

    // 静态方法用于快速初始化
    static init(formId, options) {
        return new FormHandler(formId, options);
    }
}

// 自动初始化页面上的表单
document.addEventListener('DOMContentLoaded', () => {
    const contactForm = document.getElementById('contactForm');
    if (contactForm) {
        window.contactFormHandler = new FormHandler('contactForm', {
            successMessage: '询盘发送成功！我们将在24小时内回复您。',
            errorMessage: '提交失败，请检查网络连接后重试。',
            loadingText: '发送中...'
        });
    }
});

// 导出类供其他模块使用
window.FormHandler = FormHandler;

