 */

class ProductsManager {
    constructor() {
        this.products = [];
        this.currentCategory = 'all';
        this.init();
    }

    async init() {
        await this.loadProducts();
        this.renderProducts();
        this.setupEventListeners();
        this.setupLightbox();
    }

    async loadProducts() {
        // 模拟产品数据 - 实际应用中应从API获取
        this.products = [
            {
                id: 1,
                name: '纯棉多层纱巾',
                nameEn: 'Cotton Multi-layer Towel',
                category: 'towels',
                description: '120cm×120cm，6层纯棉，超强吸水性，柔软亲肤',
                descriptionEn: '120cm×120cm, 6-layer pure cotton, super absorbent, soft and skin-friendly',
                price: '¥8.50',
