                            </div>
                        </div>
                    </div>
                </div>
            `;
        });

        container.innerHTML = productsHTML;

        // 重新初始化事件监听器
        this.setupProductCardEvents();
    }

    filterProductsByCategory() {
        if (this.currentCategory === 'all') {
            return this.products;
        }
        return this.products.filter(product => product.category === this.currentCategory);
    }

    getCategoryText(category, isZh = true) {
        const categories = {
            'towels': isZh ? '纯棉纱巾' : 'Cotton Towels',
            'gift-sets': isZh ? '婴儿礼盒' : 'Baby Gift Sets',
            'clothing': isZh ? '婴儿服饰' : 'Baby Clothing'
        };
        return categories[category] || category;
    }

    setupEventListeners() {
        // 类别筛选按钮
        document.querySelectorAll('.category-btn').forEach(button => {
            button.addEventListener('click', (e) => {
                const category = e.currentTarget.dataset.category;
                this.setCategory(category);
            });
        });

        // 语言切换时重新渲染
        if (window.i18n) {
            document.addEventListener('languageChanged', () => {
                this.renderProducts();
            });
        }
    }

    setupProductCardEvents() {
        // 查看详情按钮
        document.querySelectorAll('.view-details-btn').forEach(button => {
            button.addEventListener('click', (e) => {
                const productId = e.currentTarget.dataset.productId;
                this.showProductDetails(productId);
            });
        });

        // 立即询价按钮
        document.querySelectorAll('.inquiry-btn').forEach(button => {
            button.addEventListener('click', (e) => {
                const productId = e.currentTarget.dataset.productId;
                this.startInquiry(productId);
            });
        });
    }

    setupLightbox() {
        // Lightbox2已经通过CDN引入，这里只需要确保图片链接正确
        // 实际使用时，需要确保图片存在
    }

    setCategory(category) {
        this.currentCategory = category;

        // 更新按钮状态
        document.querySelectorAll('.category-btn').forEach(btn => {
            btn.classList.remove('active');
            if (btn.dataset.category === category) {
                btn.classList.add('active');
            }
        });

        // 重新渲染产品
        this.renderProducts();

        // 滚动到产品区域
        const productsSection = document.querySelector('.products-grid');
        if (productsSection) {
            productsSection.scrollIntoView({ behavior: 'smooth' });
        }
    }

    showProductDetails(productId) {
        const product = this.products.find(p => p.id == productId);
        if (!product) return;

        const currentLang = window.i18n ? window.i18n.getCurrentLanguage() : 'zh';
        const isZh = currentLang === 'zh';

        // 创建模态框内容
        const modalContent = `
            <div class="modal fade" id="productModal" tabindex="-1">
                <div class="modal-dialog modal-lg modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title fw-bold">${isZh ? product.name : product.nameEn}</h5>
                            <button type="button" class="btn-close" data-bs-dismiss="modal"></button>
                        </div>
                        <div class="modal-body">
                            <div class="row">
                                <div class="col-md-6">
                                    <div class="product-modal-image mb-3">
                                        <div class="image-placeholder bg-light rounded d-flex align-items-center justify-content-center" style="height: 300px;">
                                            <i class="bi bi-image display-1 text-muted"></i>
                                        </div>
                                    </div>
                                </div>
                                <div class="col-md-6">
                                    <div class="product-info">
                                        <div class="d-flex justify-content-between align-items-center mb-3">
                                            <span class="product-category-badge">${this.getCategoryText(product.category, isZh)}</span>
                                            <span class="product-price-lg text-primary fw-bold fs-4">${isZh ? product.price : product.priceEn}</span>
                                        </div>

                                        <p class="mb-4">${isZh ? product.description : product.descriptionEn}</p>

                                        <div class="mb-4">
                                            <h6 class="fw-bold mb-3" data-i18n="products.allFeatures">全部特点</h6>
                                            <div class="row">
                                                ${(isZh ? product.features : product.featuresEn).map(feature => `
                                                    <div class="col-md-6 mb-2">
                                                        <div class="d-flex align-items-center">
                                                            <i class="bi bi-check-circle-fill text-success me-2"></i>
                                                            <span>${feature}</span>
                                                        </div>
                                                    </div>
                                                `).join('')}
                                            </div>
                                        </div>

                                        <div class="product-specs-details">
                                            <h6 class="fw-bold mb-3" data-i18n="products.specifications">规格参数</h6>
                                            <div class="row">
                                                <div class="col-md-6 mb-2">
                                                    <span class="text-muted" data-i18n="products.moq">起订量:</span>
                                                    <span class="fw-medium ms-2">${isZh ? product.moq : product.moqEn}</span>
                                                </div>
                                                <div class="col-md-6 mb-2">
                                                    <span class="text-muted" data-i18n="products.category">类别:</span>
                                                    <span class="fw-medium ms-2">${this.getCategoryText(product.category, isZh)}</span>
                                                </div>
                                                <div class="col-md-6 mb-2">
                                                    <span class="text-muted" data-i18n="products.leadTime">交期:</span>
                                                    <span class="fw-medium ms-2">${isZh ? '30-45天' : '30-45 days'}</span>
                                                </div>
                                                <div class="col-md-6 mb-2">
                                                    <span class="text-muted" data-i18n="products.payment">付款方式:</span>
                                                    <span class="fw-medium ms-2">${isZh ? 'T/T, L/C' : 'T/T, L/C'}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div class="modal-footer">
                            <button type="button" class="btn btn-secondary" data-bs-dismiss="modal" data-i18n="products.close">关闭</button>
                            <button type="button" class="btn btn-primary" onclick="productsManager.startInquiry(${product.id})" data-i18n="products.inquiry">立即询价</button>
                        </div>
                    </div>
                </div>
            </div>
        `;

        // 创建并显示模态框
        let modal = document.getElementById('productModal');
        if (modal) {
            modal.remove();
        }

        document.body.insertAdjacentHTML('beforeend', modalContent);
        modal = document.getElementById('productModal');

        // 初始化模态框
        const modalInstance = new bootstrap.Modal(modal);
        modalInstance.show();

        // 模态框关闭时清理
        modal.addEventListener('hidden.bs.modal', () => {
            modal.remove();
        });
    }

    startInquiry(productId) {
        const product = this.products.find(p => p.id == productId);
        if (!product) return;

        const currentLang = window.i18n ? window.i18n.getCurrentLanguage() : 'zh';
        const productName = currentLang === 'zh' ? product.name : product.nameEn;

        // 跳转到联系页面并填充产品信息
        window.location.href = `contact.html?product=${encodeURIComponent(productName)}&category=${product.category}`;
    }
}

// 创建全局实例
window.productsManager = new ProductsManager();

// 导出类供其他模块使用
window.ProductsManager = ProductsManager;
